export function requireAuth(req: Request, res: Response, next: NextFunction): void {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith("Bearer ")) {
    res.status(401).json({ error: "Unauthorized" });
    return;
  }
  const token = authHeader.slice(7);
  try {
    req.user = jwt.verify(token, JWT_SECRET) as JwtPayload;
    next();
  } catch {
    res.status(401).json({ error: "Invalid token" });
  }
}
```

---

### Step 2 — Create `src/routes/auth.ts`

Use Node's built-in `crypto.createHash("sha256")` for password hashing (no bcrypt).

**`POST /auth/register`**
- Validate `username`, `email`, `password` present → 400 if missing
- Check for duplicate username in `users` array → 409 if taken
- Hash password, push new `User` to `users` array
- Sign JWT with `{ id, username }` payload
- Return `201 { token, user: { id, username, email } }` — **no `password` field**

**`POST /auth/login`**
- Look up user by username → 401 if not found
- Hash the submitted password and compare to stored hash → 401 if mismatch
- Sign JWT with `{ id, username }` payload
- Return `200 { token }`

Note: Seed users in `db.ts` have plaintext passwords. The tests only log in with users they've just registered (so both sides are hashed), meaning seed user logins are not tested and this is not a concern.

```typescript
import { Router } from "express";
import { createHash } from "crypto";
import jwt from "jsonwebtoken";
import { users, nextId } from "../db.js";
import { User } from "../types.js";
import { JWT_SECRET } from "../middleware/auth.js";

const router = Router();

function hashPassword(password: string): string {
  return createHash("sha256").update(password).digest("hex");
}

router.post("/register", (req, res) => { ... });  // as above
router.post("/login",    (req, res) => { ... });  // as above

export { router as authRouter };
```

---

### Step 3 — Modify `src/routes/posts.ts`

1. Import `requireAuth` from `"../middleware/auth.js"`.
2. Add `requireAuth` as inline middleware on **POST, PUT, DELETE** only (GET routes stay public).
3. **POST `/`** — replace `userId: userId || 1` with `userId: req.user!.id` (ignore any `userId` in the request body; the token is authoritative).
4. **PUT `/:id`** — after the 404 check, add: `if (posts[index].userId !== req.user!.id) { res.status(403).json(...); return; }`.
5. **DELETE `/:id`** — after the 404 check, add: `if (posts[index].userId !== req.user!.id) { res.status(403).json(...); return; }`.

Route signature examples:
```typescript
router.post("/",    requireAuth, (req, res) => { ... });
router.put("/:id",  requireAuth, (req, res) => { ... });
router.delete("/:id", requireAuth, (req, res) => { ... });
```

---

### Step 4 — Modify `src/routes/comments.ts`

Same pattern as posts:

1. Import `requireAuth`.
2. Apply `requireAuth` to **POST `/posts/:postId/comments`**, **PUT `/comments/:id`**, **DELETE `/comments/:id`** (GET routes stay public).
3. **POST** — replace `userId: userId || 1` with `userId: req.user!.id`.
4. **PUT** — add ownership check after 404: `if (comments[index].userId !== req.user!.id) → 403`.
5. **DELETE** — add ownership check after 404: `if (comments[index].userId !== req.user!.id) → 403`.

---

### Step 5 — Modify `src/app.ts`

Add two lines:

```typescript
import { authRouter } from "./routes/auth.js";
// ...
app.use("/auth", authRouter);   // mount before /posts and commentsRouter
```

---

## Key Design Notes

- **Import paths** use `.js` extensions throughout (required by `"module": "Node16"` + `"type": "module"` in package.json).
- **Global type augmentation** lives in `src/middleware/auth.ts`. Because `"include": ["src"]` in tsconfig, this augmentation applies to all route files automatically — no extra import needed for the type itself.
- **Test isolation**: Vitest runs each test file in its own worker, so in-memory db state is not shared between `auth.test.ts`, `posts.test.ts`, and `comments.test.ts`. Existing test assertions (e.g., exactly 2 comments on post 1) remain valid.
- **Existing POST/PUT tests in the existing test files**: there are none — `posts.test.ts` and `comments.test.ts` only test GET endpoints, so adding auth guards to mutating routes does not break them.

---

## Verification

```bash
npm test
```

All three test suites should pass:
- `tests/posts.test.ts` — 5 existing GET tests ✓
- `tests/comments.test.ts` — 4 existing GET tests ✓
- `tests/auth.test.ts` — 16 new auth tests ✓ (registration, login, protected routes, ownership for posts and comments)

